const agentOutput = $input.first().json;
const preparedData = $("Prepare AI Input").first().json;

let response = "";
if (agentOutput.output) {
  response = agentOutput.output;
} else if (typeof agentOutput === "string") {
  response = agentOutput;
} else {
  response = JSON.stringify(agentOutput);
}

const previousLog = preparedData.meals_log || "";
const previousCalories = preparedData.total_calories || 0;
const previousProtein = preparedData.total_protein || 0;
const previousCarbs = preparedData.total_carbs || 0;
const previousFat = preparedData.total_fat || 0;

if (preparedData.isRestart || response.toLowerCase().includes("day restarted")) {
  return [{
    json: {
      date: preparedData.currentDate,
      chat_id: preparedData.chatId,
      total_calories: 0,
      total_protein: 0,
      total_carbs: 0,
      total_fat: 0,
      meals_log: "",
      ai_response: response
    }
  }];
}

const mealMatch = response.match(/Meal: (.+)/);
const caloriesMatch = response.match(/Calories: (\d+) kcal/);
const proteinMatch = response.match(/Protein: (\d+) g/);
const carbsMatch = response.match(/Carbs: (\d+) g/);
const fatMatch = response.match(/Fat: (\d+) g/);

const totalCaloriesMatch = response.match(/Daily Total:[\s\S]*?Calories: (\d+) kcal/);
const totalProteinMatch = response.match(/Daily Total:[\s\S]*?Protein: (\d+) g/);
const totalCarbsMatch = response.match(/Daily Total:[\s\S]*?Carbs: (\d+) g/);
const totalFatMatch = response.match(/Daily Total:[\s\S]*?Fat: (\d+) g/);

const mealName = mealMatch ? mealMatch[1] : null;
const mealCalories = caloriesMatch ? parseInt(caloriesMatch[1]) : 0;
const mealProtein = proteinMatch ? parseInt(proteinMatch[1]) : 0;
const mealCarbs = carbsMatch ? parseInt(carbsMatch[1]) : 0;
const mealFat = fatMatch ? parseInt(fatMatch[1]) : 0;

let updatedLog = previousLog;
if (mealName && mealCalories > 0) {
  const newMealEntry = `${mealName} (${mealCalories} kcal, ${mealProtein}g protein)`;
  updatedLog = previousLog ? `${previousLog}; ${newMealEntry}` : newMealEntry;
}

return [{
  json: {
    date: preparedData.currentDate,
    chat_id: preparedData.chatId,
    total_calories: totalCaloriesMatch ? parseInt(totalCaloriesMatch[1]) : previousCalories + mealCalories,
    total_protein: totalProteinMatch ? parseInt(totalProteinMatch[1]) : previousProtein + mealProtein,
    total_carbs: totalCarbsMatch ? parseInt(totalCarbsMatch[1]) : previousCarbs + mealCarbs,
    total_fat: totalFatMatch ? parseInt(totalFatMatch[1]) : previousFat + mealFat,
    meals_log: updatedLog,
    ai_response: response
  }
}];

const messageData = $("Get Current Date").first().json;
const logData = $("Fetch Today Food Log").all();
const message = messageData.message;

let result = {
  currentDate: messageData.currentDate,
  chatId: messageData.chatId,
  sessionKey: messageData.sessionKey,
  hasPhoto: messageData.hasPhoto,
  hasVoice: messageData.hasVoice,
  hasText: !!messageData.messageText,
  messageText: messageData.messageText || "",
  fileId: null,
  total_calories: 0,
  total_protein: 0,
  total_carbs: 0,
  total_fat: 0,
  meals_log: "",
  userInput: "",
  isRestart: false,
  isWeeklySummary: false
};

if (message.photo && message.photo.length > 0) {
  result.fileId = message.photo[message.photo.length - 1].file_id;
} else if (message.voice) {
  result.fileId = message.voice.file_id;
}

const msgLower = (messageData.messageText || "").toLowerCase();
if (msgLower.includes("restart") && (msgLower.includes("day") || msgLower.includes("today"))) {
  result.isRestart = true;
  result.userInput = "restart the day";
  return [{ json: result }];
}

if (msgLower.includes("week") && (msgLower.includes("summary") || msgLower.includes("show"))) {
  result.isWeeklySummary = true;
  result.userInput = "show weekly summary";
  return [{ json: result }];
}

if (logData.length > 0 && logData[0].json.date) {
  const log = logData[0].json;
  result.total_calories = log.total_calories || 0;
  result.total_protein = log.total_protein || 0;
  result.total_carbs = log.total_carbs || 0;
  result.total_fat = log.total_fat || 0;
  result.meals_log = log.meals_log || "";
}

if (result.hasPhoto && result.messageText) {
  result.userInput = result.messageText + " (see attached image)";
} else if (result.hasPhoto) {
  result.userInput = "(see attached image)";
} else if (result.hasVoice) {
  result.userInput = "(voice note - will be transcribed)";
} else {
  result.userInput = result.messageText;
}

return [{ json: result }];

const data = $input.first().json;
const text = (data.messageText || "").toLowerCase();

function parseYesNo(keyword) {
  const pattern = new RegExp(keyword + "[:\\s]*(yes|no|good|bad|ok|great|poor)", "i");
  const match = text.match(pattern);
  if (!match) return null;
  const value = match[1].toLowerCase();
  if (["yes", "good", "ok", "great"].includes(value)) return "yes";
  if (["no", "bad", "poor"].includes(value)) return "no";
  return value;
}

return [{
  json: {
    date: data.currentDate,
    chat_id: data.chatId,
    workout: parseYesNo("workout"),
    steps_10k: parseYesNo("steps"),
    reading: parseYesNo("reading"),
    supplements: parseYesNo("supplements"),
    mindfulness: parseYesNo("mindfulness"),
    sleep_quality: parseYesNo("sleep")
  }
}];

